{
  UNIT_bomber_initiate_end_sequence(unit, 1);
}

//----- (00401670) --------------------------------------------------------
void __fastcall UNIT_mode_bomber_depart(Unit *unit)
{
  UNIT_bomber_initiate_end_sequence(unit, 0);
}

