//----- (00402F30) --------------------------------------------------------
void __fastcall MSG_building_generic(
        Task *receiver,
        Task *sender,
        TaskMessageType message,
        void *payload)
{
  Unit *unit2; // ebp
  Unit *unit; // esi
  MobdPoint *rally; // eax
  Entity *entity; // ecx
  int v8; // edx
  int v9; // eax
  Task *task; // [esp-Ch] [ebp-18h]
  int player_num; // [esp-4h] [ebp-10h]

  unit2 = nullptr;
  unit = (Unit *)receiver->ctx;
  if ( sender )
    unit2 = (Unit *)sender->ctx;
  if ( !unit->destroyed )
  {
    if ( unit->mode == UNIT_mode_building_under_construction && message == TaskMessage_AdvanceConstructionStage )
    {
      if ( payload == (void *)1 )
      {
        ENT_anim_set_frame(unit->entity, unit->stats->mobd_lookup_offset_attack, 1);
      }
      else if ( payload == (void *)2 )
      {
        ENT_anim_set_frame(unit->entity, unit->stats->mobd_lookup_offset_attack, 2);
      }
      else if ( payload == (void *)3 )
      {
        unit->mode = unit->mode_arrive;
      }
    }
    else
    {
      switch ( message )
      {
        case TaskMessage_Attacked:
          UNIT_on_attacked_default((Unit *)receiver->ctx, (Unit *)payload);
          if ( g_player_num == unit->player_num && !unit->cplc_spawn_param )
          {
            unit->cplc_spawn_param = 2000;
            if ( GAME_player_is_evolved() )
              SOUND_play(SoundId_129, 0, g_sfx_vol, 16, nullptr);
            else
              SOUND_play(SoundId_20, 0, g_sfx_vol, 16, nullptr);
          }
          break;
        case TaskMessage_ReceiveDamage:
          UNIT_apply_damage_ex(unit, (Entity *)payload, UINT_mode_building_exploding);
          UNIT_building_status_bar_update_health(unit);
          break;
        case TaskMessage_Sabotage:
          UNIT_sabotage(unit, (Unit *)payload, UINT_mode_building_exploding);
          break;
        case TaskMessage_EscortBegin_or_SaveGame:
          UNIT_on_escort_begin((Unit *)receiver->ctx, (Unit *)payload);
          break;
        case TaskMessage_EscortEnd_or_LoadGame:
          UNIT_on_escort_end((Unit *)receiver->ctx, (Unit *)payload);
          break;
        case TaskMessage_UnitSelected_or_UiLeftClick:
          UNIT_on_selected((Unit *)receiver->ctx);
          break;
        case TaskMessage_UnitDeselected_or_SaveLoadScrollDown_or_ShowNotificationBox:
          UNIT_on_deselected((Unit *)receiver->ctx);
          break;
        case TaskMessage_ShowHint_or_SaveLoadScrollUp:
          UNIT_show_hint((Unit *)receiver->ctx);
          break;
        case TaskMessage_Destroy:
          if ( unit->hitpoints > 0 )            // inlined
          {
            task = unit->task;
            unit->hitpoints = 0;
            TSK_yield(task, TaskWait_Interval, 1);
            unit->hitpoints = 0;
            unit->mode = UINT_mode_building_exploding;
            unit->destroyed = 1;
          }
          break;
        case TaskMessage_UnitReady:
          unit->entity->is_collidable = 1;
          rally = unit->mobd_anchors.rally;
          entity = unit->entity;
          v8 = entity->x + rally->x;
          v9 = entity->y + rally->y;
          player_num = unit->player_num;
          if ( player_num == g_player_num )
          {
            if ( ENT_create_by_unit_type((UnitType)payload, v8, v9, player_num) )
            {
              if ( GAME_player_is_evolved() )
                SOUND_play(SoundId_Mute_UnitReady, 0, g_sfx_vol, 16, nullptr);
              else
                SOUND_play(SoundId_Surv_UnitReady, 0, g_sfx_vol, 16, nullptr);
              UI_show_notification_box(nullptr, "Unit Ready");
            }
            else
            {
              UI_show_notification_box(nullptr, "Couldn't create new unit");
            }
          }
          else
          {
            ENT_create_by_unit_type((UnitType)payload, v8, v9, player_num);
          }
          break;
        case TaskMessage_BuildingComplete:
          if ( sender != receiver && unit2->player_num == unit->player_num )
            TSK_send_message(receiver, TaskMessage_BroadcastBuildingComplete, nullptr, sender);
          break;
        case TaskMessage_BroadcastBuildingComplete: {
          BuildingState *state = (BuildingState *)unit->state;
          state->same_building_count += 1;
          break;
        }
        default:
          return;
      }
    }
  }
}

