  unit->task->channel = TaskChannel_None;
  entity = unit->entity;
  unit->unit_id = 0;
  entity->x_speed = 0;
  unit->entity->y_speed = 0;
  SCHRAP_explosion_building(unit);
  SCHRAP_create(unit);
  v5 = unit->task;
  unit->mode = UNIT_mode_tech_bunker_cleanup;
