//----- (00407F40) --------------------------------------------------------
void __cdecl UNIT_hut_tick(Task *task)
{
  Unit *unit; // esi
  int cplc_spawn_param; // eax

  unit = (Unit *)task->ctx;
  if ( !unit )
  {
    unit = UNIT_create(task);
    UNIT_rendering_default(unit);
    cplc_spawn_param = unit->cplc_spawn_param;
    unit->multi_purpose_field_1 = 24576;
    switch ( cplc_spawn_param )
    {
      case 1:
        unit->orientation = MobdOrientation_NNE;
        break;
      case 2:
        unit->orientation = MobdOrientation_NE;
        break;
      case 3:
        unit->orientation = MobdOrientation_NE|MobdOrientation_NNE;
        break;
      case 4:
        unit->orientation = MobdOrientation_E;
        break;
      default:
        unit->orientation = MobdOrientation_N;
        break;
    }
    unit->task->message_handler = MSG_hut;
    unit->mode = UNIT_mode_hut_init;
  }
  ((void (__thiscall *)(Unit *))unit->mode)(unit);
}

//----- (00407FD0) --------------------------------------------------------
void __fastcall MSG_drillrig(Task *receiver, Task *sender, TaskMessageType message, void *payload)
{
  Unit *unit; // esi

  unit = (Unit *)receiver->ctx;
  if ( !unit->destroyed )
  {
    switch ( message )
    {
      case TaskMessage_Attacked:
        if ( g_player_num == unit->player_num && !unit->cplc_spawn_param )
        {
          unit->cplc_spawn_param = 1500;
          if ( GAME_player_is_evolved() )
            SOUND_play(SoundId_128, 0, g_sfx_vol, 16, nullptr);
          else
            SOUND_play(SoundId_56, 0, g_sfx_vol, 16, nullptr);
        }
        break;
      case TaskMessage_ReceiveDamage:
        UNIT_apply_damage_ex(unit, (Entity *)payload, UNIT_mode_drillrig_on_death);
        UNIT_building_status_bar_update_health(unit);
        break;
      case TaskMessage_Destroy:
        UNIT_destroy((Unit *)receiver->ctx, UNIT_mode_drillrig_on_death);
        break;
      default:
        if ( message != TaskMessage_AttackOrder_or_QuitGame )
          MSG_building_generic(receiver, sender, message, payload);
        break;
    }
  }
}

//----- (004080A0) --------------------------------------------------------
void __cdecl UNIT_drillrig_tick(Task *task)
{
  Unit *unit; // esi
  OilPatch *patch; // eax
  int hp; // eax
  int cplc_spawn_param; // eax

  unit = (Unit *)task->ctx;
  if ( !g_level_loading_lock )
  {
    if ( !unit )
    {
      unit = UNIT_create(task);
      unit->task->message_handler = MSG_drillrig;
      SHROUD_reveal(unit);
      unit->task->channel = TaskChannel_Drillrig;
      UNIT_building_init(unit, 2, nullptr, nullptr);
      unit->entity->is_collidable = 1;
      patch = OIL_find_nearest_patch(unit->entity->x, unit->entity->y);
      if ( patch )
      {
        unit->entity->x = (patch->entity->x & 0xFFFFE000) + 0x1000;
        unit->entity->y = (patch->entity->y & 0xFFFFE000) + 0x1000;
      }
      unit->_u1.oil_patch = patch;
      unit->entity->is_collidable = 1;

      BuildingState *state = (BuildingState *)unit->state;
      state->ctx = OIL_find_patch_at_tile(unit->entity->x, unit->entity->y);
      if ( unit->entity->cplc_spawn_params )
        unit->mode = UNIT_mode_drillrig_place_without_deployment;// if pre-placed -> skip deployment animation
      else
        unit->mode = UNIT_mode_drillrig_deploy;
      hp = task->entity->building_ctx.hitpoints;
      if ( hp )
      {
        unit->hitpoints = hp;
        UNIT_building_status_bar_update_health(unit);
      }
      unit->cplc_spawn_param = 0;               // damage to the drillrig voice alert cooldown
    }
    ((void (__thiscall *)(Unit *))unit->mode)(unit);
    cplc_spawn_param = unit->cplc_spawn_param;
    if ( cplc_spawn_param )
      unit->cplc_spawn_param = cplc_spawn_param - 1;
  }
}

//----- (004081C0) --------------------------------------------------------
void __fastcall UNIT_mode_drillrig_deploy(Unit *unit)
{
  Turret *turret; // eax
  Task *task; // ecx

  unit->entity->x_speed = 0;
  unit->entity->y_speed = 0;
  turret = unit->turret;
  if ( turret )
  {
    turret->entity->rn->flags |= RenderNode_Skip;
    ENT_anim_set_frame(unit->entity, unit->stats->mobd_lookup_offset_attack, g_angle_to_orientation[unit->orientation]);
    task = unit->task;
    unit->mode = UNIT_mode_drillrig_adjust_to_oil_patch_position;
    TSK_yield(task, TaskWait_AnimCompletion, 0);
  }
  else
  {
    TSK_yield(unit->task, TaskWait_Interval, 1);
  }
}

//----- (00408240) --------------------------------------------------------
void __fastcall UNIT_mode_drillrig_place_without_deployment(Unit *unit)
{
  Task *task; // [esp-Ch] [ebp-Ch]

  task = unit->task;
  unit->mode = UNIT_mode_drillrig_adjust_to_oil_patch_position;
  TSK_yield(task, TaskWait_Interval, 1);
}

//----- (00408260) --------------------------------------------------------
void __fastcall UNIT_mode_drillrig_adjust_to_oil_patch_position(Unit *unit)
{
  OilPatch *nearest_patch; // eax
  Turret *turret; // eax

  if ( !unit->_u1.oil_patch )
  {
    unit->entity->is_collidable = 1;
    nearest_patch = OIL_find_nearest_patch(unit->entity->x, unit->entity->y);
    if ( nearest_patch )
    {
      unit->entity->x = (nearest_patch->entity->x & 0xFFFFE000) + 0x1000; // BUG repeated accross drillrig code
      unit->entity->y = (nearest_patch->entity->y & 0xFFFFE000) + 0x1000;
    }
  }
  turret = unit->turret;
  if ( turret )
    turret->entity->rn->flags &= ~RenderNode_Skip;
  if ( unit->entity->cplc_spawn_params )
  {
    unit->mode = UNIT_mode_building_snap_to_grid;
  }
  else
  {
    unit->mode = UNIT_mode_building_idle_tick;
    BOXD_building_claim_area(unit);
  }
  unit->entity->is_collidable = 1;

  OilPatch *patch = OIL_find_patch_at_tile(unit->entity->x, unit->entity->y);
  patch->drillrig = unit;
  patch->drillrig_unit_id = unit->unit_id;

  BuildingState *state = (BuildingState *)unit->state;
  state->ctx = patch;

  UNIT_mode_building_idle_tick(unit);
}

