//----- (00410E40) --------------------------------------------------------
void __fastcall UNIT_tanker_status_bar_init(Unit *unit)
{
  TankerState *state = unit->state;
  if (!state) {
    return;
  }

  // 297 bytes (9 for the struct + 288 for the pixels)
  // the original had 300: +3 - alignment? was probably a macro to align MobdImageData to the upper aligned bound
  // not sure it's still worth doing it - let the memory allocator figure it out
  MobdImageData *img = TSK_alloc(unit->task, sizeof(MobdImageData) + hp_tanker_stride * hp_tanker_height);
  if (!img) {
    return;
  }

  img->width = hp_tanker_stride;
  img->height = hp_tanker_height;
  img->format = Sprt_Raw;
  state->img = img;

  unit->overlay_sprt.flags = 0;
  unit->overlay_sprt.bitmap = img;
  unit->overlay_sprt.blitter = REND_mode_sprt_draw;
  unit->overlay_rn = REND_node_add(unit->entity, (RenderTransform)REND_transform_tanker_overlay);
  unit->overlay_rn->payload = unit;

  memset(img->pixels, 0x01, hp_tanker_stride * hp_tanker_height);

  uint8_t *row1 = img->pixels;
  uint8_t *row8 = img->pixels + 8 * hp_tanker_stride;
  memset(row1, HP_BAR_BORDER_TOP, hp_tanker_stride);
  memset(row8, HP_BAR_OIL_TOP, hp_tanker_stride);

  for (int y = 1; y < 8; ++y) {
    uint8_t *row = img->pixels + y * hp_tanker_stride;
    row[0] = HP_BAR_BORDER_LFT;
    row[hp_tanker_stride - 1] = HP_BAR_BORDER_RGT;
  }

  uint8_t *row5 = img->pixels + 5 * hp_tanker_stride + 2; // +2 for borders on each side
  uint8_t *row6 = row5 + hp_tanker_stride;
  int oil_fill_width = hp_tanker_width * state->oil_loaded / 500;

  memset(row5,                  HP_BAR_OIL_TOP,    oil_fill_width);
  memset(row5 + oil_fill_width, HP_BAR_BORDER_TOP, hp_tanker_width - oil_fill_width);
  memset(row6,                  HP_BAR_OIL_BOT,    oil_fill_width);
  memset(row6 + oil_fill_width, HP_BAR_BORDER_BOT, hp_tanker_width - oil_fill_width);

  uint8_t *row2 = img->pixels + 2 * hp_tanker_stride + 2; // +2 for borders on each side
  uint8_t *row3 = row2 + hp_tanker_stride;
  int hp_fill_width = hp_tanker_width * unit->hitpoints / unit->stats->hitpoints;
  int hp_color_idx = 4 * hp_fill_width / hp_tanker_width;
  uint8_t c1 = g_healthbar_fill_color_top[hp_color_idx];
  uint8_t c2 = g_healthbar_fill_color_bottom[hp_color_idx];

  memset(row2,                 c1,                hp_fill_width);
  memset(row2 + hp_fill_width, HP_BAR_BORDER_TOP, hp_tanker_width - hp_fill_width);
  memset(row3,                 c2,                hp_fill_width);
  memset(row3 + hp_fill_width, HP_BAR_BORDER_BOT, hp_tanker_width - hp_fill_width);

  unit->overlay_rn->flags |= RenderNode_Skip;
}

//----- (00411040) --------------------------------------------------------
void UNIT_status_bar_short_sprites_init()
{
  for (int vet = 0; vet < MAX_VETERANCY_LEVELS; ++vet) {
    uint8_t fill_top = 0xFF;
    uint8_t fill_bot = 0xFF;
    int color_idx = 0;

    for (int frame = 0; frame < NUM_INFANTRY_HP_BAR_FRAMES; ++frame) {
      MobdImageData *img = malloc(sizeof(MobdImageData) + hp_infantry_stride * hp_infantry_height);
      assert(img);

      img->width = hp_infantry_stride;
      img->height = hp_infantry_height;
      img->format = Sprt_Raw;
      g_healthbar_by_veterancy_short[vet][frame] = img;

      memset(img->pixels, 0x01, hp_infantry_stride * hp_infantry_height);

      uint8_t *row0 = img->pixels;
      uint8_t *row5 = img->pixels + 5 * hp_infantry_stride;
      memset(row0, g_healthbar_border_color_top[vet], hp_infantry_stride);
      memset(row5, g_healthbar_border_color_bottom[vet], hp_infantry_stride);

      for (int y = 1; y <= 4; ++y) {
        uint8_t *row = img->pixels + y * hp_infantry_stride;
        row[0] = g_healthbar_border_color_top[vet];
        row[hp_infantry_stride - 1] = g_healthbar_border_color_bottom[vet];
      }

      if (frame % 2 == 0) {
        fill_top = g_healthbar_border_color_top[color_idx];
        fill_bot = g_healthbar_border_color_bottom[color_idx];
        if (color_idx < 4) {
          color_idx++;
        }
      }

      int fill_w = frame + 1;  // frame 0 -> 1px bar (minimal), frame 11 -> 12px bar (full)
      uint8_t *row_top = &img->pixels[2 * hp_infantry_stride + 2];
      uint8_t *row_bot = &img->pixels[3 * hp_infantry_stride + 2];

      memset(row_top,          fill_top,          fill_w);
      memset(row_top + fill_w, HP_BAR_BORDER_TOP, hp_infantry_width - fill_w);
      memset(row_bot,          fill_bot,          fill_w);
      memset(row_bot + fill_w, HP_BAR_BORDER_BOT, hp_infantry_width - fill_w);
    }
  }
}

//----- (00411200) --------------------------------------------------------
void UNIT_status_bar_wide_sprites_init()
{
  for (int vet = 0; vet < MAX_VETERANCY_LEVELS; ++vet) {
    uint8_t fill_top = 0xFF;
    uint8_t fill_bot = 0xFF;
    int color_idx = 0;

    for (int frame = 0; frame < NUM_VEHICLES_HP_BAR_FRAMES; ++frame) {
      MobdImageData *img = malloc(sizeof(MobdImageData) + hp_vehicle_stride * hp_vehicle_height);
      assert(img);

      img->width = hp_vehicle_stride;
      img->height = hp_vehicle_height;
      img->format = Sprt_Raw;
      g_healthbar_by_veterancy_wide[vet][frame] = img;

      memset(img->pixels, 0x01, hp_vehicle_stride * hp_vehicle_height);

      memset(&img->pixels[0 * hp_vehicle_stride], g_healthbar_border_color_top[vet], hp_vehicle_stride);
      memset(&img->pixels[5 * hp_vehicle_stride], g_healthbar_border_color_bottom[vet], hp_vehicle_stride);

      for (int y = 1; y <= 4; ++y) {
        uint8_t *row = img->pixels + y * hp_vehicle_stride;
        row[0] = g_healthbar_border_color_top[vet];
        row[hp_vehicle_stride - 1] = g_healthbar_border_color_bottom[vet];
      }

      if (frame % 5 == 0) {
        fill_top = g_healthbar_border_color_top[color_idx];
        fill_bot = g_healthbar_border_color_bottom[color_idx];
        if (color_idx < 4) {
          color_idx++;
        }
      }

      int fill_w = frame + 1;  // frame 0 -> 1px bar (minimal), frame 27 -> 28px bar (full)
      uint8_t *row_top = &img->pixels[2 * hp_vehicle_stride + 2];
      uint8_t *row_bot = &img->pixels[3 * hp_vehicle_stride + 2];

      memset(row_top,          fill_top,          fill_w);
      memset(row_top + fill_w, HP_BAR_BORDER_TOP, hp_vehicle_width - fill_w);
      memset(row_bot,          fill_bot,          fill_w);
      memset(row_bot + fill_w, HP_BAR_BORDER_BOT, hp_vehicle_width - fill_w);
    }
  }
}

//----- (004113D0) --------------------------------------------------------
void UNIT_status_bar_sprites_cleanup()
{
  for (int i = 0; i < MAX_VETERANCY_LEVELS; ++i) {
    for (int j = 0; j < 12; ++j) {
      free(g_healthbar_by_veterancy_short[i][j]);
    }
    for (int j = 0; j < 28; ++j) {
      free(g_healthbar_by_veterancy_wide[i][j]);
    }
  }
}

