//----- (00412190) --------------------------------------------------------
BOOL REND_should_render()
{
  if ( !g_rend_limit_rate )
    return 1;

  int time = (int)timeGetTime();
  if (g_time_next_tick_time < time)
  {
    if ( ++g_render_num_frames_skipped < 4 )
    {
      return 0;
    }
    else
    {
      g_time_next_tick_time = time;
      g_render_num_frames_skipped = 0;
      return 1;
    }
  }
  else
  {
    g_render_num_frames_skipped = 0;
    return 1;
  }
}

