//----- (00412B70) --------------------------------------------------------
void __cdecl UNIT_infantry_tick(Task *task)
{
  Unit *unit; // esi
  Entity *entity; // eax
  int x; // ecx
  int y; // eax
  Unit *order_target; // eax
  int unit_id; // eax

  if ( !g_level_loading_lock )
  {
    unit = (Unit *)task->ctx;
    if ( !unit )
    {
      unit = UNIT_create(task);
      UNIT_init(unit);
      TURRET_vehicle_init(unit);
      UNIT_rendering_default(unit);
    }
    if ( unit->unit_id == -1 )
      DBG_on_invalid_unit_tick(1);
    ((void (__thiscall *)(Unit *))unit->mode)(unit);
    entity = unit->entity;
    x = entity->x;
    if ( x < 0 || x >= g_map_num_tiles_x << 13 || (y = entity->y, y < 0) || y >= g_map_num_tiles_y << 13 )
    {
      unit->entity->x = 25600;
      unit->entity->y = 25600;
      unit->mode = UNIT_mode_destroy_init;
    }
    if ( (((unsigned __int8)unit->unit_id ^ (unsigned __int8)g_opportunity_timer) & 0x3F) == 0 )// &3F = 64 values max
                                                // 0 only when unit_id == timer
                                                // meaning each unit fires 1 in 64 frames - optimization to not serach for targets too often
      UNIT_scan_for_targets_of_opportunity(unit);
    if ( unit->unit_id == -1 )
      DBG_on_invalid_unit_tick(0);
    order_target = unit->order_target;
    if ( order_target )
    {
      unit_id = order_target->unit_id;
      if ( unit_id )
      {
        if ( unit_id == unit->order_target_id )
          unit->_u1 = *(UnitUnion1 *)&unit->order_target->entity->x;
      }
    }
  }
}

