// Path validator (as opposed to path builder BOXD_build_path_to) - with focus on immediate tile occupancy and prediction,
// seeing if any deviations from the path built are needed in case of crowding etc
BOOL __fastcall BOXD_can_path_to(int start_x, int start_y, int target_x, int target_y, Unit *unit)
{
  UnitSize size; // esi

  size = unit->stats->size;
  if ( size == UnitSize_Regular || size == UnitSize_Small )
    return BOXD_can_path_to_regular(start_x, start_y, target_x, target_y, unit);
  if ( size == UnitSize_XL )
    return BOXD_can_path_to_xl(start_x, start_y, target_x, target_y, unit);
  return 0;
}

