//----- (0041CAE0) --------------------------------------------------------
BOOL __fastcall GAME_load_init(const char *filename, LevelId level_id)
{
  if ( g_is_game_loading || g_is_game_saving )
    return 0;
  strcpy(g_current_savegame_filename, filename);
  g_saveload_level_id = level_id;
  g_is_game_loading = 1;
  return 1;
}

//----- (0041CB30) --------------------------------------------------------
