//----- (00421E20) --------------------------------------------------------
BOOL GAME_is_machine_shop_maxed()
{
  return g_machineshop_levels.max_level >= 5;
}

//----- (00421E30) --------------------------------------------------------
void __fastcall MSG_machine_shop_upgrades(
        Task *receiver,
        Task *sender,
        TaskMessageType message,
        void *payload)
{
  Unit *unit; // esi
  BuildingState *state; // eax
  SidebarFactoryProduction *prod; // ebx

  unit = (Unit *)receiver->ctx;
  state = (BuildingState *)unit->state;
  prod = state->prod;
  state->upgrade_level = min(5, state->upgrade_level + 1);
  if ( unit->player_num == g_player_num )
  {
    g_machineshop_levels.num_buildings_by_level[state->upgrade_level - 1] -= 1;
    g_machineshop_levels.num_buildings_by_level[state->upgrade_level] += 1;
    if ( state->upgrade_level > g_machineshop_levels.max_level )
      g_machineshop_levels.max_level = state->upgrade_level;
    switch ( state->upgrade_level )
    {
      case 2:
        UI_sidebar_prod_enable_unit(prod, UnitType_Surv_AtvFlamethrower, 2568);
        break;
      case 3:
        UI_sidebar_prod_enable_unit(prod, UnitType_Surv_AnacondaTank, 2624);
        UI_sidebar_prod_enable_unit(prod, UnitType_Surv_Tanker, 2616);
        break;
      case 4:
        UI_sidebar_prod_enable_unit(prod, UnitType_Surv_BarrageCraft, 2560);
        break;
      case 5:
        UI_sidebar_prod_enable_unit(prod, UnitType_Surv_AutocannonTank, 2600);
        if ( GAME_outpost_is_maxed() )
          AIRSTRIKE_try_unlock();
        break;
      default:
        break;
    }
  }
  UNIT_status_bar_update_tech(unit);
  MSG_building_generic(receiver, sender, message, payload);
}
