void CPLC_exec_all()
{
  TaskType i; // esi

  for ( i = 0; i < TaskType_Max; ++i )
  {
    if ( i != TaskType_Camera )
      CPLC_exec_with_objects(i);
  }
}

//----- (00423DF0) --------------------------------------------------------
void CPLC_exec_subset()
{
  TaskType i; // esi

  for ( i = 0; i < TaskType_Max; ++i )
  {
    if ( i != TaskType_Camera )
    {
      if ( i == TaskType_MOBD_6_UiSymbols
        || i == TaskType_KeyboardDispatcher
        || i == TaskType_IngameMenuController
        || i == TaskType_SidebarLoop
        || i == TaskType_Mobd_15_MissionOutcomeModal
        || i == TaskType_MissionOutcomeSequence
        || i == TaskType_CursorLoop
        || i == TaskType_NewMissionsSelect
        || i == TaskType_Reinforcements
        || i == TaskType_SidebarTooltip
        || i == TaskType_FontItalic )
      {
        CPLC_exec_with_objects(i);
      }
      else
      {
        CPLC_exec_without_objects(i);
      }
    }
  }
}
