//----- (004278D0) --------------------------------------------------------
void __fastcall MSG_mobile_base(Task *receiver, Task *sender, TaskMessageType message, void *payload)
{
  Unit *unit; // esi

  unit = (Unit *)receiver->ctx;
  if ( !unit->destroyed )
  {
    switch ( message )
    {
      case TaskMessage_Attacked:
        UNIT_on_attacked_default(unit, (Unit *)payload);
        break;
      case TaskMessage_ReceiveDamage:
        UNIT_on_damage(unit, (Entity *)payload);
        UNIT_status_bar_update_frame(unit);
        break;
      case TaskMessage_EscortBegin_or_SaveGame:
        UNIT_on_escort_begin(unit, (Unit *)payload);
        break;
      case TaskMessage_EscortEnd_or_LoadGame:
        UNIT_on_escort_end(unit, (Unit *)payload);
        break;
      case TaskMessage_UnitSelected_or_UiLeftClick:
        UNIT_on_selected(unit);
        break;
      case TaskMessage_UnitDeselected_or_SaveLoadScrollDown_or_ShowNotificationBox:
        UNIT_on_deselected(unit);
        break;
      case TaskMessage_ShowHint_or_SaveLoadScrollUp:
        UNIT_show_hint(unit);
        break;
      case TaskMessage_BuildingPlacementModeBegin_or_BackToMenu:
        UNIT_mobile_base_plant(unit);
        break;
      case TaskMessage_MoveOrder_or_SoundSettings_or_DoSaveGame:
        UNIT_on_move_order(unit, (MoveOrderPayload *)payload);
        break;
      default:
        return;
    }
  }
}

