//----- (00448EF0) --------------------------------------------------------
void __fastcall MSG_unit_order_dispatcher(
        Task *receiver,
        Task *sender,
        TaskMessageType message,
        void *payload)
{
  UnitOrderCtx *ctx; // ecx
  SelectionNode *next; // eax

  ctx = (UnitOrderCtx *)receiver->ctx;
  if ( message == TaskMessage_UnitDeselected_or_SaveLoadScrollDown_or_ShowNotificationBox )
  {
    next = ctx->sentinel.next;
    if ( (UnitOrderCtx *)ctx->sentinel.next != ctx )
    {
      while ( next->unit_task != sender )
      {
        next = next->next;
        if ( next == (SelectionNode *)ctx )
          return;
      }
      next->next->prev = next->prev;
      next->prev->next = next->next;
      next->next = ctx->selection_head;
      ctx->selection_head = next;
    }
  }
}

